import React from "react";
import { useNavigate } from "react-router-dom";

export default function Welcome(){

  const navigate = useNavigate();

  return (
    <div className="center">

      <h1>CampusBeacon</h1>
      <p>Campus Lost & Found System</p>

      <button onClick={() => navigate("/login")}>
        Login
      </button>

    </div>
  );

}
